  ('locality-6f0ba476-moex-00235', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲向乙借貸周轉新臺幣（下同）1,000萬元，約定週年利率百分之三十，一年後償還本息。甲央請 好友丙擔任甲對乙之借款債務之連帶保證人，丙並同意拋棄其先訴抗辯權。俟清償期屆至，甲無 力償還本息，雖甲對乙有另一筆已屆清償期之貨款債權 1,100 萬元，但甲拋棄互為抵銷之抗辯， 乙旋訴請丙連帶償還借款本息。下列敘述何者正確？', '["乙得訴請丙連帶償還1,200萬元", "當乙訴請丙連帶償還借款本息時，丙得以甲對乙之貨款債權主張抵銷，抵銷後丙僅須償還乙 60萬元", "丙得主張約定利率超過週年利率百分之十六者，乙對於超過部分之利息無請求權", "當乙訴請丙連帶償還借款本息時，因甲已拋棄其抵銷抗辯，丙無從以甲對乙之貨款債權主張抵 銷，故丙應償還乙1,160萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00236', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於保證補充性之敘述，何者錯誤？', '["保證為從債務，債權人原則上應先向主債務人請求清償，且須經執行而無效果，始得請求保證 人清償", "保證人得拋棄先訴抗辯權，該拋棄為有相對人之單獨行為，應向債權人為之", "保證人拋棄先訴抗辯權者，須於債權人同意後，始生效力", "主債務人受破產宣告，保證人不得主張先訴抗辯權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00237', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列何者非屬權利之原始取得？', '["無主物先占", "法院拍賣", "動產所有權之時效取得", "土地徵收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00238', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於遺產分割之敘述，何者錯誤？', '["繼承人有數人時，在分割遺產前，各繼承人對於遺產全部為公同共有", "繼承人得隨時請求分割遺產。但法律另有規定或契約另有訂定者，不在此限", "各繼承人對於繼承之公同共有不動產之分割請求權，性質上為具有一身專屬權利", "分割遺產之行為，因其發生權利之變動，其係屬處分行為之一種"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00239', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲向乙銀行貸款新臺幣1,000萬元，雙方約定甲應以其所有之A屋為乙銀行設定普通抵押權。關 於雙方就A屋設定普通抵押權之約定，下列敘述何者正確？', '["債權契約", "物權契約", "準物權契約", "準處分行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00240', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲所有之A土地，由乙在其上建有B屋一棟。下列敘述何者正確？', '["倘若乙係於甲將A土地設定普通抵押權於丙前，基於地上權而在甲所有之A土地上建築B屋， 嗣乙將B屋出售給丁並辦理移轉登記，丙得對B屋主張併付拍賣", "倘若乙係於甲將A土地設定普通抵押權於丙後，基於地上權而在甲所有之A土地上建築B屋， 嗣乙將B屋出售給丁並辦理移轉登記，丙不得對B屋主張併付拍賣", "倘若乙係於甲將A土地設定普通抵押權於丙後，基於地上權而在甲所有之A土地上建築B屋， 嗣乙將B屋出售給甲並辦理移轉登記，丙得對B屋主張併付拍賣", "倘若乙係於甲將A土地設定普通抵押權於丙前，無權在甲所有之A土地上建築B屋，嗣乙將 B屋出售給丁並辦理移轉登記，丙得對B屋主張併付拍賣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00241', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '下列關於不動產役權特性之敘述，何者錯誤？', '["不動產役權不得由需役不動產分離而為讓與，此為不動產役權從屬性之表現", "不動產役權不得由供役不動產分離而為其他權利之標的物，此為不動產役權從屬性之表現", "需役不動產經分割者，原則上不動產役權為各部分之利益仍為存續，此為不動產役權不可分性 之表現", "供役不動產經分割者，原則上不動產役權就其各部分仍為存續，此為不動產役權不可分性之 表現 31670 32070"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00242', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '抵押權人於債權已屆清償期，而未受清償者，得實行抵押權。下列何者不屬抵押權之實行方法？', '["法院拍賣", "流押契約之執行", "拍賣以外之方法", "行使抵押權之必要保全處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00243', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲、乙、丙為三兄弟，甲與丁結婚，丙與戊結婚，乙未婚但認領庚。己為戊之妹。下列關於親屬 關係之敘述，何者錯誤？', '["丁庚間無親屬關係", "庚戊間為姻親關係", "己庚間無親屬關係", "丁戊間為姻親關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00244', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-9b7ab1bb', 'sub-locality-6f0ba476-02', NULL, 'single_choice', '甲男乙女為夫妻，因乙女與丁男通姦，甲、乙乃於民國（下同）105年3月1日辦妥協議離婚登 記。105年4月1日乙女與丙男辦理結婚登記。同年12月1日乙女生下一子戊。事實上，戊之生 父為丁。下列敘述何者錯誤？', '["戊可推定為甲男之子", "戊可推定為丙男之子", "丁得認領戊", "戊可同時推定為甲男、丙男之子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "2f6b91418648", "answer_pdf_sha1": "84e151aedd97", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
